#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Define the structure for the tree
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to calculate the number of ways to assign weights to the edges of the tree
long long calculateWays(Node* root, int* conditions, int n, int Q) {
    // Base case: If the tree is empty, return 1
    if (root == NULL) {
        return 1;
    }

    // Initialize the dynamic programming table
    long long* dp = (long long*) malloc(sizeof(long long) * (n + 1));
    for (int i = 0; i <= n; i++) {
        dp[i] = 0;
    }

    // Iterate over each condition and update the dynamic programming table
    for (int i = 0; i < Q; i++) {
        int u = conditions[i * 3];
        int v = conditions[i * 3 + 1];
        int x = conditions[i * 3 + 2];
        // Update the dynamic programming table based on the condition
        if (x == 0) {
            // If the sum of the weights of the edges in the path from node u to node v should be even
            dp[u] = (dp[u] + dp[v]) % MOD;
        } else {
            // If the sum of the weights of the edges in the path from node u to node v should be odd
            dp[u] = (dp[u] + (MOD - dp[v])) % MOD;
        }
    }

    // Calculate the number of ways to assign weights to the edges of the tree
    long long ways = 1;
    for (int i = 1; i <= n; i++) {
        ways = (ways * dp[i]) % MOD;
    }

    // Free the memory allocated for the dynamic programming table
    free(dp);

    return ways;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, Q;
        scanf("%d %d", &n, &Q);
        Node* root = NULL;
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            // Create a new node and add it to the tree
            Node* newNode = createNode(u);
            if (root == NULL) {
                root = newNode;
            } else {
                // Add the new node to the tree
                Node* temp = root;
                while (temp->right != NULL) {
                    temp = temp->right;
                }
                temp->right = newNode;
            }
        }
        int* conditions = (int*) malloc(sizeof(int) * Q * 3);
        for (int i = 0; i < Q; i++) {
            int u, v, x;
            scanf("%d %d %d", &u, &v, &x);
            conditions[i * 3] = u;
            conditions[i * 3 + 1] = v;
            conditions[i * 3 + 2] = x;
        }
        long long ways = calculateWays(root, conditions, n, Q);
        printf("%lld\n", ways);
        // Free the memory allocated for the tree and the conditions
        free(conditions);
        while (root != NULL) {
            Node* temp = root;
            root = root->right;
            free(temp);
        }
    }
    return 0;
}

